function isRetryableRpc(e){let c=String(e?.code||''),m=String(e?.message||'');return RETRYABLE_RPC.has(c)||e?.retryable===true||m.includes('HTTP 502')||m.includes('runtime_unavailable')||m.includes('runtime_busy')||m.includes('too_many_requests')}
async function invokeFn(name,body,max=4){for(let i=0;i<max;i++)try{return await dzmm.fn.invoke(name,body)}catch(e){if(!isRetryableRpc(e)||i===max-1)throw e;await new Promise(r=>setTimeout(r,1000*2**i+Math.random()*300))}}
function openTree(){let p=S.player,names={paladin:'圣骑士十字架',mage:'大魔法师魔法书',ranger:'游侠机械苍鹰',lewdSaintess:'淫靡圣女魔神淫像',scytheMaiden:'琦琦·冥月镰灵'};$('treeTitle').textContent=names[p.cls];$('treeSub').textContent=`金币：${S.gold}。每项最高 ${RELIC_MAX} 级，固定神器出生即佩戴，升级后强化职业特色。`;$('treeNodes').innerHTML=RELIC_TREE[p.cls].map(n=>{let lv=Math.min(RELIC_MAX,S.relicLv[n[0]]||0),full=lv>=RELIC_MAX,cost=n[3]*(lv+1);return `<button class="choice node" data-relic="${n[0]}" ${full?'disabled':''}><h2>✦ ${n[1]} 等级${lv}/${RELIC_MAX}</h2><p>${n[2]}</p><small>${full?'已满级':`升级消耗 ${cost} 金币`}</small></button>`}).join('');$('relicTree').classList.remove('hidden');S.paused=true}
function buyRelic(id){let p=S.player,node=RELIC_TREE[p.cls].find(n=>n[0]===id),lv=Math.min(RELIC_MAX,S.relicLv[id]||0);if(lv>=RELIC_MAX)return;let cost=node[3]*(lv+1);if(S.gold<cost)return;S.gold-=cost;S.relicLv[id]=lv+1;if(id==='faith'){applyArtifactStats();p.hp=p.max}if(id==='idol')gainLust(25);openTree();updateHud();saveGame()}
function safeName(...vals){for(let v of vals){let s=String(v||'').trim();if(s&&s!=='null'&&s!=='undefined'&&!/^匿名/.test(s))return s.slice(0,16)}return'匿名勇士'}
