function renderEquipTabs(){ensureEquipBulkState();let tabs=[['all','全部'],['set','套装'],['unique','暗金'],['sacrifice','祭品'],['wearable','本职业']],n=equipBulkPick.size;$('equipmentPanel').querySelector('.equipTabs').innerHTML=tabs.map(t=>`<button data-eq-filter="${t[0]}" class="${equipFilter===t[0]?'active':''}">${t[1]}</button>`).join('')+`<button data-eq-bulk-toggle class="eqBulkBtn ${equipBulk?'danger':''}">${equipBulk?`分解(${n})`:'分解'}</button>${equipBulk?'<button data-eq-bulk-all>全选</button><button data-eq-bulk-cancel>取消</button><button class="eqBulkGear" data-eq-bulk-settings title="分解过滤">⚙</button>':''}`}
function renderEquipGrid(filter='all'){ensureEquipBulkState();equipFilter=filter;renderEquipTabs();let cls=equipCls(),seasonLv=window.Season?.level?Season.level():20,eq=Equipment.data().equipped?.[cls]||{},worn=new Set(Object.values(eq)),items=equipItems(filter).filter(it=>!worn.has(it.uid));$('equipGrid').innerHTML=items.map(it=>{let locked=seasonLv<(it.requiredLevel||1),pick=equipBulkPick.has(it.uid),label=`${eqNameText(it)} Lv.${it.level} ${Equipment.SLOT_CN[it.slot]}`;return `<button class="eqCard ${it.rarity} ${locked?'levelLocked':''} ${equipBulk?'bulkMode':''} ${pick?'bulkPick':''}" ${equipBulk?`data-eq-bulk="${it.uid}"`:`data-eq-detail="${it.uid}"`} title="${esc(label)}" aria-label="${esc(label)}">${Equipment.iconHtml(it)}</button>`}).join('')||'<div class="choice">暂无可显示装备。已穿戴装备会显示在上方穿戴栏中。</div>'}
function renderEquipment(filter=equipFilter){ensureEquipBulkState();let cls=equipCls(),eq=Equipment.data().equipped?.[cls]||{},seasonLv=window.Season?.level?Season.level():1,seasonName=window.Season?.cfg?Season.cfg().name:'赛季',equipped=Equipment.SLOTS.map(slot=>Equipment.data().items.find(x=>x.uid===eq[slot])).map(x=>x&&Equipment.hydrate(x)),sacSlots=Equipment.SACRIFICE_SLOTS||['sacrifice1','sacrifice2'],sacrifices=sacSlots.map(slot=>Equipment.data().items.find(x=>x.uid===eq[slot])).map(x=>x&&Equipment.hydrate(x));$('equipTitle').textContent=`${seasonName}装备`;$('equipMenuBtn').textContent=`${seasonName}装备`;$('equipSub').innerHTML=`<button class="equipClassSwitch ${cls}" data-eq-class-switch>${Equipment.CLS_CN[cls]}</button><button class="equipAttrSwitch" data-eq-attr-panel>属性</button><span>切换流派 · 赛季等级 ${seasonLv}/${window.Season?.cap?Season.cap():20}</span>`;$('equipStats').innerHTML='';let sacHtml=sacSlots.map((slot,i)=>{let it=sacrifices[i];return `<button class="eqSlot sacrificeSlot slot-${slot} ${it?'filled '+eqRarityClass(it):'empty'}" ${it?`data-eq-worn-detail="${it.uid}"`:'data-sacrifice-empty="1"'}><span>${Equipment.SLOT_CN[slot]}</span>${it?Equipment.iconHtml(it)+eqNameHtml(it):'<em>空</em>'}</button>`}).join('');$('equipSlots').innerHTML=`<div class="equipMannequin"><div class="equipHalo"></div><img class="equipFigure ${cls}" src="${AS[CLASSES[cls].card]}" alt="${Equipment.CLS_CN[cls]}"><small>当前穿戴</small></div>${sacHtml}`+Equipment.SLOTS.map((slot,i)=>{let it=equipped[i];return `<button class="eqSlot slot-${slot} ${it?'filled '+eqRarityClass(it):'empty'}" ${it?`data-eq-worn-detail="${it.uid}"`:''}><span>${Equipment.SLOT_CN[slot]}</span>${it?Equipment.iconHtml(it)+eqNameHtml(it):'<em>空</em>'}</button>`}).join('');renderEquipGrid(filter)}
async function openEquipment(){if(S?.run){showNotice('局内不能穿戴装备，请回到封面后进入装备仓库');return}await initBootData();ensureEquipBulkState();equipViewClass=S?.player?.cls||pendingClass||equipViewClass||'paladin';renderEquipment();$('equipmentPanel').classList.remove('hidden')}
async function equipItem(uid){if(S?.run){showNotice('局内不能穿戴装备');return}let cls=equipCls(),it=Equipment.hydrate(Equipment.data().items.find(x=>x.uid===uid)),ok=await Equipment.equip(uid,cls);if(!ok){showNotice(it?.class&&it.class!==cls?'职业不符，无法穿戴':`赛季等级不足，需要 Lv.${it?.requiredLevel||1}`);showStoreEquipDetail(uid);return}renderEquipment();showStoreEquipDetail(uid)}
async function unequipItem(slot){if(S?.run){showNotice('局内不能卸下装备');return}let cls=equipCls(),uid=Equipment.data().equipped?.[cls]?.[slot];await Equipment.unequip(slot,cls);renderEquipment();if(uid)showStoreEquipDetail(uid)}
async function discardEquip(uid){if(S?.run){showNotice('局内不能分解装备');return}let raw=Equipment.data().items.find(x=>x.uid===uid);$('equipDetailModal').classList.add('hidden');if(!raw){renderEquipment(equipFilter);return}let gain=Equipment.disenchantValue?Equipment.disenchantValue(raw):0,ok=await Equipment.discard(uid);showNotice(ok?`装备已分解，获得 ${gain} 魔尘`:'祭品不可分解');renderEquipment(equipFilter)}
async function rerollEquipAffix(raw){if(S?.run){showNotice('局内不能重铸装备');return}let btn=document.querySelector(`[data-eq-reroll="${raw}"]`),old=btn?.textContent;if(btn){btn.disabled=true;btn.textContent='重铸中…'}let [uid,key]=(raw||'').split(':'),r=await Equipment.rerollAffix(uid,key);if(!r.ok){if(btn){btn.disabled=false;btn.textContent=old||'重铸'}showNotice(r.reason||'重铸失败');return}showNotice(`重铸完成，消耗 ${r.cost} 魔尘`);renderEquipment(equipFilter);openEquipReroll(uid)}
function toggleEquipBulk(){ensureEquipBulkState();if(!equipBulk){equipBulk=true;equipBulkPick=new Set();syncEquipBulkState();renderEquipment(equipFilter);return}discardBulkEquip()}
function cancelEquipBulk(){ensureEquipBulkState();equipBulk=false;equipBulkPick.clear();syncEquipBulkState();renderEquipment(equipFilter)}
function toggleEquipBulkPick(uid){ensureEquipBulkState();if(!equipBulk)return;let it=Equipment.hydrate(Equipment.data().items.find(x=>x.uid===uid));if(it?.rarity==='sacrifice'){showNotice('祭品不可一键分解');return}equipBulkPick.has(uid)?equipBulkPick.delete(uid):equipBulkPick.add(uid);syncEquipBulkState();renderEquipGrid(equipFilter)}
async function discardBulkEquip(){ensureEquipBulkState();if(S?.run){showNotice('局内不能分解装备');return}let ids=[...equipBulkPick].filter(uid=>Equipment.hydrate(Equipment.data().items.find(x=>x.uid===uid))?.rarity!=='sacrifice');if(!ids.length){showNotice('先选择要分解的装备');return}let gain=ids.reduce((sum,uid)=>sum+(Equipment.disenchantValue?Equipment.disenchantValue(Equipment.data().items.find(x=>x.uid===uid)):0),0);await Equipment.discardMany(ids);equipBulk=false;equipBulkPick.clear();syncEquipBulkState();showNotice(`已分解 ${ids.length} 件装备，获得 ${gain} 魔尘`);renderEquipment(equipFilter)}
function riftDropCount(layer){layer=Math.max(1,Math.floor(Number(layer)||1));return Math.round(2+layer/10)}
function riftDropForSlot(layer){layer=Math.max(1,Math.floor(Number(layer)||1));let rng=Math.random(),pSet=layer<30?0:Math.min(.30,.08+(layer-30)*.005),pUnique=layer<40?0:layer<50?.02+(layer-40)*.004:Math.min(.16,.08+(layer-50)*.0016);if(rng<pUnique)return 'unique';if(rng<pUnique+pSet)return 'set';return 'gold'}
function dropEquipmentFromBoss(x,y){let rift=S?.rift?.active,layer=rift?S.rift.layer:(S.endlessLayer||0),count=rift?riftDropCount(layer):1;if(!count){showNotice('秘境 10 层开始掉落局外装备');return}let names=[],items=[];for(let i=0;i<count;i++){let it=Equipment.rollDrop(S.player.cls,S.bossKills||1,layer,riftDropForSlot(layer,i,count));items.push(it);names.push(it.rarity==='unique'?'暗金':it.rarity==='set'?'套装':'黄金');if(!rift){let a=i*TAU/count+rand(-.18,.18),rr=rand(18,74);S.equipGround.push({x:x+Math.cos(a)*rr,y:y+Math.sin(a)*rr,item:it})}}if(!rift){showNotice(`Boss 掉落 ${count} 件装备：${names.slice(0,6).join('、')}${count>6?'…':''}`);return}S.rift.lootSaving=true;showNotice(`秘境 Boss 获得 ${count} 件装备，正在放入赛季装备仓库...`);(async()=>{let failed=[];for(const it of items){try{await Equipment.addItem(it)}catch(e){console.error('秘境装备入库失败:',e.code,e.message,e.stack);failed.push(it)}}if(failed.length){failed.forEach((it,i)=>{let a=i*TAU/failed.length+rand(-.18,.18),rr=rand(18,74);S.equipGround.push({x:x+Math.cos(a)*rr,y:y+Math.sin(a)*rr,item:it})});showNotice(`已入库 ${count-failed.length} 件，${failed.length} 件入库失败已掉落地面`)}else showNotice(`秘境 Boss 装备已入库：${names.slice(0,6).join('、')}${count>6?'…':''}`);S.rift.lootSaving=false;saveGame()})()}
function renderAltar(){let picks=new Set(S.altarPick||[]);$('altarSub').textContent=`污染装备 ${S.equipDrops.length} 件。本次最多净化 2 件，未净化装备继续留在本局。`;$('altarList').innerHTML=S.equipDrops.map(x=>{let it=Equipment.hydrate(x);return `<button class="eqCard ${it.rarity} ${picks.has(it.uid)?'altarPick':''}" data-altar-pick="${it.uid}">${Equipment.iconHtml(it)}${eqNameHtml(it)}<div class="eqMini">Lv.${it.level} · 需赛季${it.requiredLevel||1} · ${Equipment.SLOT_CN[it.slot]}${it.setName?' · '+esc(it.setName):''}</div></button>`}).join('')||'<div class="choice">暂无污染装备。</div>'}
function openAltar(){if(!S?.equipDrops?.length)return;S.paused=true;S.altarPick=[];S.dropsSinceAltar=0;renderAltar();$('altarPanel').classList.remove('hidden')}
function toggleAltar(uid){let p=S.altarPick||[],i=p.indexOf(uid);if(i>=0)p.splice(i,1);else if(p.length<2)p.push(uid);S.altarPick=p;renderAltar()}
async function cleanAltar(){let pick=new Set(S.altarPick||[]);for(const it of S.equipDrops.filter(x=>pick.has(x.uid)))await Equipment.addItem(it);S.equipDrops=S.equipDrops.filter(x=>!pick.has(x.uid));$('altarPanel').classList.add('hidden');showNotice(`净化完成：${pick.size} 件装备进入本赛季仓库`);saveGame();S.paused=false}
function openInventory(){statDetailSource=null;let p=S.player,b=artifactBonus(),eqs=(S.equipDrops||[]).map(Equipment.hydrate);$('artifactDetail').classList.add('hidden');$('artifactDetail').innerHTML='';$('equipDetailModal').classList.add('hidden');$('statusBox').innerHTML=`<div class="statusPortrait"><img src="${AS[CLASSES[p.cls].card]}" alt="${p.job}"></div><div class="equipSlots">${[0,1].map(i=>{let id=S.artifacts[i],a=id&&artDef(id),idx=id?artIndex(id):0;return `<button class="equipSlot" ${id?`data-unequip="${id}"`:''}>${id?artIcon(idx):'<span>空槽位</span>'}<b>${a?a[1]:'通用神器'}</b></button>`}).join('')}</div><div class="statList"><div><span>职业</span><b>${p.job}</b></div><div><span>等级</span><b>${p.lv}</b></div>${(()=>{let d=statBreakdown();return statLine('生命',d.生命.total)+statLine('伤害',d.伤害.total)+statLine('防御',d.防御.total)+statLine('速度',d.速度.total)})()}</div><div class="evoGuide"><h3>本局进化</h3><div class="evoGrid">${Object.keys(S.evolutions||{}).map(id=>`<div class="evoItem ready"><b>${EVOLUTIONS[id].name}</b><small>${EVOLUTIONS[id].desc}</small></div>`).join("")||'<div class="evoItem">尚未完成技能进化</div>'}</div></div>`;$('bagGrid').innerHTML=Array.from({length:Math.max(24,S.bag.length+eqs.length)},(_,i)=>{if(i<S.bag.length){let id=S.bag[i],a=id&&artDef(id),idx=id?artIndex(id):0,eq=id&&S.artifacts.includes(id);return `<button class="bagCell ${id?'owned':''} ${eq?'equipped':''}" ${id?`data-artifact="${id}"`:''}>${id?artIcon(idx):'<span>空</span>'}<small>${a?a[1]:''}</small></button>`}let it=eqs[i-S.bag.length];return `<button class="bagCell ${it?'owned polluted':''}" ${it?`data-run-equip="${it.uid}"`:''}>${it?Equipment.iconHtml(it):'<span>空</span>'}<small>${it?eqNameText(it):'空'}</small></button>`}).join('');$('inventory').classList.remove('hidden');S.paused=true}
function showArtifactDetail(id){let a=artDef(id),i=artIndex(id),eq=S.artifacts.includes(id),full=S.artifacts.length>=ARTIFACT_LIMIT;if(!a)return;$('artifactDetail').classList.remove('hidden');$('artifactDetail').innerHTML=`<h2>${artIcon(i)} ${esc(a[1])}</h2><p>${esc(a[2])}</p><p><b>状态：</b>${eq?'已装备':full?'装备槽已满':'可装备'}</p><button class="detailEquipBtn" data-equip-artifact="${id}" ${eq||full?'disabled':''}>${eq?'已装备':full?'槽位已满':'佩戴'}</button>`}
function equipArtifact(id){if(S.artifacts.includes(id))return;if(S.artifacts.length>=ARTIFACT_LIMIT)return;S.artifacts.push(id);S.artCd[id]=0;applyArtifactStats();openInventory();showArtifactDetail(id);updateHud();saveGame()}
function unequipArtifact(id){S.artifacts=S.artifacts.filter(x=>x!==id);delete S.artCd[id];applyArtifactStats();openInventory();updateHud();saveGame()}
function updateModeLabel(){ $('modeBtn').textContent=control.auto?'自动·'+autoStyle():'手动模式' }
function cycleAutoStyle(){control.style=(control.style+1)%3;control.auto=true;control.target=null;control.x=0;control.y=0;moveStick(0,0);$('controls').classList.add('auto');updateModeLabel();showNotice('自动策略：'+autoStyle())}
function setMode(auto){control.auto=auto;updateModeLabel();$('controls').classList.toggle('auto',auto);if(auto){control.target=null;control.x=0;control.y=0;moveStick(0,0)}}
function moveStick(x,y){$('stick').style.transform=`translate(${x*32}px,${y*32}px)`}
function joyMove(e){control.target=null;let r=$('joy').getBoundingClientRect(),cx=r.left+r.width/2,cy=r.top+r.height/2,dx=e.clientX-cx,dy=e.clientY-cy,m=Math.hypot(dx,dy),lim=r.width*.36;if(m>lim){dx=dx/m*lim;dy=dy/m*lim}control.x=dx/lim;control.y=dy/lim;moveStick(control.x,control.y)}
function tapMove(e){if(!S||!S.run||S.paused||S.over)return;let r=canvas.getBoundingClientRect(),x=(e.clientX-r.left)*W/r.width+CAMX,y=(e.clientY-r.top)*H/r.height+CAMY;control.auto=false;control.target={x:clamp(x,24,WORLD_W-24),y:clamp(y,62,WORLD_H-24)};control.x=0;control.y=0;moveStick(0,0);updateModeLabel();$('controls').classList.remove('auto')}
function renderProgression(){Progression.render($('progressionPanel'),renderClassCards)}
function openProgressionTree(){Progression.renderTree($('progressTree'),()=>{renderClassCards();renderProgression()});$('progressionModal').classList.remove('hidden')}
